import { useEffect, useRef, useState } from 'react';

const testimonials = [
  {
    name: 'Priya Sharma',
    role: 'Marathon Runner',
    text: "After my ACL surgery, I thought my running days were over. JK Physiotherapy's team had me back on the trail in 5 months. Their dedication is unmatched.",
    initials: 'PS',
    rating: 5,
  },
  {
    name: 'Rahul Mehra',
    role: 'Software Engineer',
    text: "Chronic lower back pain from desk work was ruining my life. Three months of targeted therapy here, and I'm pain-free. Truly life-changing care.",
    initials: 'RM',
    rating: 5,
  },
  {
    name: 'Anita Verma',
    role: 'Retired Teacher',
    text: 'Post-stroke rehabilitation at JK gave me my independence back. The therapists are patient, skilled, and genuinely caring. I am forever grateful.',
    initials: 'AV',
    rating: 5,
  },
  {
    name: 'Karan Joshi',
    role: 'Cricket Player',
    text: "Shoulder injury during a match — JK had me back playing in record time. Their sports rehab program is world-class. Highly recommend to all athletes.",
    initials: 'KJ',
    rating: 5,
  },
];

const Stars = ({ count = 5 }) => (
  <div className="flex gap-0.5">
    {Array.from({ length: count }).map((_, i) => (
      <svg key={i} className="w-4 h-4 text-amber-400" fill="currentColor" viewBox="0 0 20 20">
        <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
      </svg>
    ))}
  </div>
);

const Testimonials = () => {
  const [active, setActive] = useState(0);
  const [visible, setVisible] = useState(false);
  const sectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setActive((p) => (p + 1) % testimonials.length);
    }, 4000);
    return () => clearInterval(timer);
  }, []);

  return (
    <section id="testimonials" className="py-24 bg-white" ref={sectionRef}>
      <div className="max-w-6xl mx-auto px-6">
        {/* Header */}
        <div className={`text-center mb-16 fade-up ${visible ? 'visible' : ''}`}>
          <div className="inline-block bg-amber-50 text-amber-600 text-xs font-bold tracking-widest uppercase px-4 py-2 rounded-full mb-4">
            Patient Stories
          </div>
          <h2 className="text-4xl font-bold text-slate-800">
            Real Recoveries, <span className="text-brand">Real Lives</span>
          </h2>
        </div>

        <div className={`fade-up ${visible ? 'visible' : ''}`}>
          {/* Featured Testimonial */}
          <div
            className="border border-slate-100 rounded-3xl p-10 mb-8 max-w-3xl mx-auto relative"
            style={{ background: 'linear-gradient(135deg, #f8fafc 0%, #fff5f540 100%)' }}
          >
            <div
              className="text-red-200 font-serif absolute top-6 left-8"
              style={{ fontSize: '72px', lineHeight: 1 }}
            >
              "
            </div>
            <div key={active} className="testimonial-enter pt-4">
              <p className="text-slate-600 text-lg leading-relaxed mb-8 italic">
                {testimonials[active].text}
              </p>
              <div className="flex items-center justify-between flex-wrap gap-4">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-brand rounded-2xl flex items-center justify-center text-white font-bold">
                    {testimonials[active].initials}
                  </div>
                  <div>
                    <div className="font-semibold text-slate-800">{testimonials[active].name}</div>
                    <div className="text-sm text-slate-400">{testimonials[active].role}</div>
                  </div>
                </div>
                <Stars count={testimonials[active].rating} />
              </div>
            </div>
          </div>

          {/* Dots */}
          <div className="flex justify-center gap-2 mb-10">
            {testimonials.map((_, i) => (
              <button
                key={i}
                onClick={() => setActive(i)}
                className="rounded-full border-none cursor-pointer transition-all"
                style={{
                  backgroundColor: i === active ? '#db261d' : '#CBD5E1',
                  width: i === active ? '32px' : '10px',
                  height: '10px',
                  transition: 'all 0.3s ease',
                }}
              />
            ))}
          </div>

          {/* Mini Cards Grid */}
          <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {testimonials.map((t, i) => (
              <button
                key={t.name}
                onClick={() => setActive(i)}
                className="text-left p-5 rounded-2xl border cursor-pointer bg-white transition-all"
                style={{
                  borderColor: i === active ? '#fca5a5' : '#F1F5F9',
                  backgroundColor: i === active ? '#fff5f5' : 'white',
                  boxShadow: i === active ? '0 2px 8px rgba(219,38,29,0.1)' : 'none',
                  transition: 'all 0.3s ease',
                }}
              >
                <div className="flex items-center gap-3 mb-3">
                  <div
                    className="w-9 h-9 rounded-xl flex items-center justify-center text-sm font-bold"
                    style={{
                      backgroundColor: i === active ? '#db261d' : '#F1F5F9',
                      color: i === active ? 'white' : '#475569',
                    }}
                  >
                    {t.initials}
                  </div>
                  <div>
                    <div className="text-sm font-semibold text-slate-700">{t.name}</div>
                    <div className="text-xs text-slate-400">{t.role}</div>
                  </div>
                </div>
                <Stars />
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Testimonials;
